/**
 * Расширение глобального пространства имён Express.
 * Добавляет пользовательские свойства к стандартным объектам Express.
 */
declare namespace Express {
	/** Расширенный интерфейс запроса Express */
	interface Request {
		/** Email аутентифицированного пользователя, извлечённый из JWT-токена */
		user?: string
	}
}
